import { useState, useEffect, useRef, useCallback, useReducer } from "react";

/* ─────────────────────────────────────────────────────────────
   PLOT TWIST: WORLD DEED — one shared Earth, ~300m tiles.
   Real coastlines (Natural Earth), quadkey grid, live trading.
   Virtual money only. Parody ads. No real anything.
   ───────────────────────────────────────────────────────────── */

const LAND_B64 = "";
const MASK_W = 2048, MASK_H = 1024;

const Z = 17;                 // parcel zoom: ~306m tiles at the equator
const N = 1 << Z;             // tiles per axis
const REGION_LEN = 8;         // shared-storage shard prefix (~150km regions)
const SAVE_KEY = "plottwist:world:v1";

const C = {
  ink: "#0A1622", panel: "#111C2B", hair: "#243146",
  ocean: "#0A2233", oceanDeep: "#081B2A", landFill: "#22384A",
  amber: "#FFC24B", text: "#E8EDF5", dim: "#8DA0B8",
};

const CLS = {
  coast: { name: "Coast",      price: 1200, rps: 5,   color: "#3FB8AF" },
  land:  { name: "Inland",     price: 400,  rps: 1.6, color: "#7BA88A" },
  water: { name: "Open water", price: 150,  rps: 0.5, color: "#4A7FA5" },
};
const FLAVOR = ["Plains", "Forest", "Highlands", "Fields", "Scrubland", "Valley"];

const RAR = [
  { name: "Common",    m: 1,   color: "#93A3B8" },
  { name: "Uncommon",  m: 1.5, color: "#5FD68B" },
  { name: "Rare",      m: 3,   color: "#5FA8F5" },
  { name: "Legendary", m: 8,   color: "#FFC24B" },
];
const LVL = ["Vacant tile", "Cottage", "Duplex", "Apartments", "Tower"];
const MAX_LVL = 4;

const ADS = [
  { brand: "Bolder Boulders", line: "Rocks, but bolder." },
  { brand: "Grandma's Artisanal Gravel", line: "Chew responsibly." },
  { brand: "InvisiBlinds", line: "Window blinds you can't see." },
  { brand: "Soup Loans", line: "Liquid assets, instantly." },
  { brand: "Pigeon Mail Pro", line: "Unlimited data. Bring crumbs." },
  { brand: "The Ladder Store", line: "This ad is a step up." },
  { brand: "Mildly Haunted Realty", line: "Every home has character(s)." },
  { brand: "Actual Cloud Storage", line: "0% uptime. 100% sky." },
];

const CITIES = [
  ["New York", 40.71, -74.01], ["London", 51.51, -0.13], ["Tokyo", 35.68, 139.69],
  ["São Paulo", -23.55, -46.63], ["Sydney", -33.87, 151.21], ["Cairo", 30.04, 31.24],
  ["Lagos", 6.52, 3.37], ["Mumbai", 19.08, 72.88],
];

const ACH = [
  { k: "deed1",  name: "First deed",     desc: "Claim your first tile" },
  { k: "deed10", name: "Landlord",       desc: "Own 10 tiles" },
  { k: "globe",  name: "Globetrotter",   desc: "Own tiles in 3+ regions" },
  { k: "lux",    name: "Legendary find", desc: "Roll a Legendary deed" },
  { k: "tower",  name: "Skyline",        desc: "Build a Tower (Lv 4)" },
  { k: "trader", name: "Trader",         desc: "Sell a tile to another player" },
  { k: "rich",   name: "Deep pockets",   desc: "Hold ₲50,000 at once" },
  { k: "streak3",name: "Regular",        desc: "3-day visit streak" },
];

/* ── math: mercator + quadkeys ──────────────────────────────── */

const MAXLAT = 85.05112878;
const lonToWx = (lon) => (lon + 180) / 360;
const latToWy = (lat) => {
  lat = Math.max(-MAXLAT, Math.min(MAXLAT, lat));
  const s = Math.sin((lat * Math.PI) / 180);
  return 0.5 - Math.log((1 + s) / (1 - s)) / (4 * Math.PI);
};
const wyToLat = (wy) => (Math.atan(Math.sinh(Math.PI * (1 - 2 * wy))) * 180) / Math.PI;

function qkOf(tx, ty) {
  let q = "";
  for (let i = Z; i > 0; i--) {
    const m = 1 << (i - 1);
    q += (tx & m ? 1 : 0) + (ty & m ? 2 : 0);
  }
  return q;
}
function txyOf(qk) {
  let tx = 0, ty = 0;
  for (const ch of qk) { tx = tx * 2 + (ch === "1" || ch === "3" ? 1 : 0); ty = ty * 2 + (ch === "2" || ch === "3" ? 1 : 0); }
  return [tx, ty];
}
const centerOfQk = (qk) => { const [tx, ty] = txyOf(qk); const n = 1 << qk.length; return [(tx + 0.5) / n, (ty + 0.5) / n]; };
const regionOf = (qk) => qk.slice(0, REGION_LEN);

function prefixesFor(camv, sz, cap = 9) {
  const out = [];
  const { s, x: ox, y: oy } = camv;
  const { w, h } = sz;
  const nR = 1 << REGION_LEN, rpx = s / nR;
  const rx0 = Math.max(0, Math.floor(-ox / rpx)), ry0 = Math.max(0, Math.floor(-oy / rpx));
  const rx1 = Math.min(nR - 1, Math.floor((w - ox) / rpx)), ry1 = Math.min(nR - 1, Math.floor((h - oy) / rpx));
  for (let ry = ry0; ry <= ry1 && out.length < cap; ry++)
    for (let rx = rx0; rx <= rx1 && out.length < cap; rx++) {
      let q = "";
      for (let i = REGION_LEN; i > 0; i--) {
        const m = 1 << (i - 1);
        q += (rx & m ? 1 : 0) + (ry & m ? 2 : 0);
      }
      out.push(q);
    }
  return out;
}

function coordLabel(qk) {
  const [wx, wy] = centerOfQk(qk);
  const lat = wyToLat(wy), lon = wx * 360 - 180;
  return `${Math.abs(lat).toFixed(2)}°${lat >= 0 ? "N" : "S"} ${Math.abs(lon).toFixed(2)}°${lon >= 0 ? "E" : "W"}`;
}

function hashQk(qk) {
  let h = 2166136261;
  for (let i = 0; i < qk.length; i++) { h ^= qk.charCodeAt(i); h = Math.imul(h, 16777619); }
  return (h >>> 0) / 4294967296;
}

/* ── economy helpers ────────────────────────────────────────── */

const rentOf = (t) => CLS[t.cls].rps * RAR[t.r].m * (1 + t.l);
const upCost = (t) => Math.round(CLS[t.cls].price * 0.8 * Math.pow(t.l + 1, 1.6));

function rollRarity() {
  const n = Math.random();
  if (n < 0.02) return 3;
  if (n < 0.1) return 2;
  if (n < 0.3) return 1;
  return 0;
}

function fmt(n) {
  n = Math.floor(n);
  if (n < 10000) return n.toLocaleString();
  if (n < 1e6) return (n / 1e3).toFixed(1) + "k";
  if (n < 1e9) return (n / 1e6).toFixed(2) + "m";
  return (n / 1e9).toFixed(2) + "b";
}
const fmt1 = (n) => (n < 100 ? n.toFixed(1) : fmt(n));

/* ── storage (window.storage w/ in-memory fallback) ─────────── */

const mem = {};
const hasStore = () => typeof window !== "undefined" && !!window.storage;
const store = {
  async get(k, s = false) {
    if (hasStore()) { try { const r = await window.storage.get(k, s); return r ? r.value : null; } catch { return null; } }
    return mem[(s ? "s:" : "") + k] ?? null;
  },
  async set(k, v, s = false) {
    if (hasStore()) { try { await window.storage.set(k, v, s); return true; } catch { return false; } }
    mem[(s ? "s:" : "") + k] = v; return true;
  },
  async list(p = "", s = false) {
    if (hasStore()) { try { const r = await window.storage.list(p, s); return (r && r.keys) || []; } catch { return []; } }
    return Object.keys(mem).filter((k) => k.startsWith((s ? "s:" : "") + p)).map((k) => (s ? k.slice(2) : k));
  },
};

const freshSave = () => ({
  v: 1, pid: "p" + Math.random().toString(36).slice(2, 10), name: "",
  bal: 2000, own: [], ach: {}, streak: 0, lastDaily: "", boostUntil: 0, lastSeen: Date.now(),
});

/* ── UI atoms ───────────────────────────────────────────────── */

const mono = { fontFamily: "ui-monospace, SFMono-Regular, Menlo, Consolas, monospace" };

function Btn({ children, onClick, disabled, tone = "amber", full, small }) {
  const tones = {
    amber: { background: C.amber, color: "#221A05" },
    ghost: { background: "transparent", color: C.text, border: `1px solid ${C.hair}` },
    danger: { background: "transparent", color: "#F08A8A", border: "1px solid #4A2A33" },
  };
  return (
    <button
      onClick={onClick}
      disabled={disabled}
      className={`rounded-lg font-semibold tracking-wide transition-opacity focus-visible:outline focus-visible:outline-2 focus-visible:outline-offset-2 ${
        small ? "px-3 py-1.5 text-xs" : "px-4 py-2.5 text-sm"
      } ${full ? "w-full" : ""} ${disabled ? "opacity-35" : "active:opacity-70"}`}
      style={{ ...mono, ...tones[tone], outlineColor: C.amber }}
    >
      {children}
    </button>
  );
}

function Chip({ color, children }) {
  return (
    <span className="pt10 rounded px-1.5 py-0.5 font-bold uppercase tracking-widest"
      style={{ ...mono, color, background: color + "1f", border: `1px solid ${color}55` }}>
      {children}
    </span>
  );
}

function Eyebrow({ children }) {
  return <div className="pt10 trk uppercase" style={{ ...mono, color: C.dim }}>{children}</div>;
}

/* ═════════════════════════════════════════════════════════════
   MAIN
   ═════════════════════════════════════════════════════════════ */

export default function PlotTwistWorld() {
  const [screen, setScreen] = useState("menu"); // menu | game
  const [hasSave, setHasSave] = useState(false);
  const [howto, setHowto] = useState(false);
  const [confirmNew, setConfirmNew] = useState(false);
  const G = useRef(null);

  useEffect(() => {
    (async () => {
      const raw = await store.get(SAVE_KEY);
      setHasSave(!!raw);
    })();
  }, []);

  const start = async (fresh) => {
    let g = null;
    const raw = await store.get(SAVE_KEY);
    if (raw && !fresh) { try { g = JSON.parse(raw); } catch { g = null; } }
    if (fresh && raw) {
      try { const old = JSON.parse(raw); g = freshSave(); g.pid = old.pid || g.pid; } catch { g = freshSave(); }
    }
    if (!g || !g.pid) g = freshSave();
    G.current = g;
    setScreen("game");
  };

  if (screen === "menu") {
    return (
      <div className="relative flex h-screen w-full flex-col items-center justify-center overflow-hidden p-6" style={{ background: C.ink, color: C.text }}>
        <style>{`.pt9{font-size:9px}.pt10{font-size:10px}.pt11{font-size:11px}.trk{letter-spacing:.22em}`}</style>
        <img src={"data:image/png;base64," + LAND_B64} alt="" className="pointer-events-none absolute inset-0 h-full w-full object-cover opacity-20" style={{ filter: "sepia(1) hue-rotate(160deg)" }} />
        <div className="relative text-center">
          <Eyebrow>One shared Earth · ~300 m tiles</Eyebrow>
          <h1 className="mb-1 mt-2 text-4xl font-bold" style={{ ...mono, color: C.amber, letterSpacing: ".04em" }}>PLOT TWIST</h1>
          <div className="pt11 trk mb-8 uppercase" style={{ ...mono, color: C.dim }}>World Deed Edition</div>
          <div className="mx-auto flex w-64 flex-col gap-2.5">
            {hasSave && <Btn full onClick={() => start(false)}>Continue</Btn>}
            <Btn full tone={hasSave ? "ghost" : "amber"} onClick={() => (hasSave ? setConfirmNew(true) : start(true))}>New game</Btn>
            <Btn full tone="ghost" onClick={() => setHowto(true)}>How to play</Btn>
          </div>
          <div className="pt9 mx-auto mt-10 max-w-xs leading-relaxed" style={{ ...mono, color: C.dim }}>
            Parody idle game. ₲ Geobux are virtual and worth nothing. The "ads" are fictional. The Earth, however, is real — you just can't have it.
          </div>
        </div>

        {howto && (
          <Modal onClose={() => setHowto(false)}>
            <Eyebrow>How to play</Eyebrow>
            <div className="mt-3 flex flex-col gap-2.5 text-sm leading-relaxed" style={{ color: C.text }}>
              <div>Zoom into anywhere on Earth until the deed grid appears, then tap a ~300 m tile and buy it. Everyone plays on the same planet — one tile, one owner.</div>
              <div>Tiles pay rent per second. Rarity is rolled when you buy (up to 8×). Build them up from cottage to tower for more rent.</div>
              <div>Trade with real players: list your tiles at any price on the open market, or buy theirs. Sales pay you even while you're offline.</div>
              <div>Coast tiles earn most, inland is steady, open water is cheap and weird. The scale bar is real — that's actually how big Greenland isn't.</div>
            </div>
            <div className="mt-4"><Btn full onClick={() => setHowto(false)}>Got it</Btn></div>
          </Modal>
        )}
        {confirmNew && (
          <Modal onClose={() => setConfirmNew(false)}>
            <Eyebrow>Start over?</Eyebrow>
            <div className="mt-3 text-sm leading-relaxed" style={{ color: C.text }}>
              This resets your wallet, streak and progress. Tiles already deeded to you stay yours on the shared world and will be re-discovered when you visit them.
            </div>
            <div className="mt-4 flex gap-2">
              <Btn full tone="ghost" onClick={() => setConfirmNew(false)}>Cancel</Btn>
              <Btn full onClick={() => { setConfirmNew(false); start(true); }}>Reset</Btn>
            </div>
          </Modal>
        )}
      </div>
    );
  }

  return <Game G={G} onExit={() => { setHasSave(true); setScreen("menu"); }} />;
}

function Modal({ children, onClose }) {
  return (
    <div className="absolute inset-0 z-20 flex items-center justify-center p-6" style={{ background: "rgba(4,9,16,0.85)" }} onClick={onClose}>
      <div className="w-full max-w-sm rounded-2xl p-5" style={{ background: C.panel, border: `1px solid ${C.hair}` }} onClick={(e) => e.stopPropagation()}>
        {children}
      </div>
    </div>
  );
}

/* ═════════════════════════════════════════════════════════════
   GAME
   ═════════════════════════════════════════════════════════════ */

function Game({ G, onExit }) {
  const [, force] = useReducer((x) => x + 1, 0);
  const [ready, setReady] = useState(false);
  const [tab, setTab] = useState("map");
  const [sel, setSel] = useState(null);          // quadkey or null
  const [roll, setRoll] = useState(null);        // {qk, phase, r}
  const [modal, setModal] = useState(null);
  const [toasts, setToasts] = useState([]);
  const [syncing, setSyncing] = useState(false);
  const [cities, setCities] = useState(false);
  const [market, setMarket] = useState({ loading: false, rows: null });
  const [lb, setLb] = useState({ loading: false, rows: null });
  const [nameDraft, setNameDraft] = useState(G.current.name || "");
  const [priceDraft, setPriceDraft] = useState("");
  const pendings = useRef([]);
  const dirty = useRef(false);
  const lastPush = useRef(0);
  const regions = useRef(new Map()); // prefix -> {t:{qk:rec}, at}
  const busyRegions = useRef(new Set());
  const persistent = hasStore();

  const reduced = typeof window !== "undefined" && window.matchMedia &&
    window.matchMedia("(prefers-reduced-motion: reduce)").matches;

  const toast = useCallback((text) => {
    const id = Math.random();
    setToasts((t) => [...t.slice(-2), { id, text }]);
    setTimeout(() => setToasts((t) => t.filter((x) => x.id !== id)), 2800);
  }, []);

  /* ── derived ── */
  const g = G.current;
  const ownMap = useRef(new Map());
  const rebuildOwn = useCallback(() => {
    ownMap.current = new Map(g.own.map((t) => [t.qk, t]));
    g.rps = g.own.reduce((s, t) => s + rentOf(t), 0);
  }, [g]);

  const netWorth = () => g.bal + g.own.reduce((s, t) => s + (t.pd || 0), 0);

  const checkAch = useCallback(() => {
    const unlock = (k, name) => { if (!g.ach[k]) { g.ach[k] = 1; toast(`Unlocked — ${name}`); dirty.current = true; } };
    const n = g.own.length;
    if (n >= 1) unlock("deed1", "First deed");
    if (n >= 10) unlock("deed10", "Landlord");
    if (new Set(g.own.map((t) => regionOf(t.qk))).size >= 3) unlock("globe", "Globetrotter");
    if (g.own.some((t) => t.r === 3)) unlock("lux", "Legendary find");
    if (g.own.some((t) => t.l >= 4)) unlock("tower", "Skyline");
    if (g.bal >= 50000) unlock("rich", "Deep pockets");
    if ((g.streak || 0) >= 3) unlock("streak3", "Regular");
  }, [g, toast]);

  const save = useCallback(async () => {
    g.lastSeen = Date.now();
    await store.set(SAVE_KEY, JSON.stringify(g));
    dirty.current = false;
  }, [g]);

  const pushLB = useCallback((forcePush) => {
    if (!g.name) return;
    const now = Date.now();
    if (!forcePush && now - lastPush.current < 30000) return;
    lastPush.current = now;
    store.set("lb:" + g.pid, JSON.stringify({ n: g.name, nw: Math.round(netWorth()), pc: g.own.length, t: now }), true);
  }, [g]);

  /* ── bank: collect sale proceeds ── */
  const collectBank = useCallback(async () => {
    const raw = await store.get("bank:" + g.pid, true);
    if (!raw) return;
    let arr = [];
    try { arr = JSON.parse(raw) || []; } catch { arr = []; }
    if (!arr.length) return;
    let sum = 0;
    for (const e of arr) {
      sum += e.amt || 0;
      const i = g.own.findIndex((t) => t.qk === e.qk);
      if (i >= 0) g.own.splice(i, 1);
    }
    rebuildOwn();
    g.bal += sum;
    if (!g.ach.trader) { g.ach.trader = 1; toast("Unlocked — Trader"); }
    dirty.current = true;
    await store.set("bank:" + g.pid, "[]", true);
    toast(`+₲${fmt(sum)} from tile sales`);
    save();
  }, [g, rebuildOwn, toast, save]);

  /* ── boot ── */
  useEffect(() => {
    (async () => {
      rebuildOwn();
      const now = Date.now();
      const dt = Math.min(Math.max(0, (now - (g.lastSeen || now)) / 1000), 8 * 3600);
      const gain = Math.floor(g.rps * dt * 0.5);
      if (dt > 120 && gain > 0) { g.bal += gain; pendings.current.push({ kind: "welcome", gain }); }
      const today = new Date().toDateString();
      if (g.lastDaily !== today) {
        const gap = g.lastDaily ? now - new Date(g.lastDaily).getTime() : Infinity;
        g.streak = gap < 48 * 3600e3 ? (g.streak || 0) + 1 : 1;
        g.lastDaily = today;
        const reward = 150 * Math.min(g.streak, 7);
        g.bal += reward;
        pendings.current.push({ kind: "daily", streak: g.streak, reward });
      }
      g.lastSeen = now;
      setReady(true);
      if (pendings.current.length) setModal(pendings.current.shift());
      dirty.current = true;
      collectBank();
    })();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  /* ── economy tick ── */
  useEffect(() => {
    if (!ready) return;
    let n = 0;
    const iv = setInterval(() => {
      const mult = Date.now() < g.boostUntil ? 2 : 1;
      if (g.rps > 0) { g.bal += (g.rps * mult) / 4; dirty.current = true; }
      n++;
      if (n % 8 === 0) checkAch();
      if (n % 32 === 0 && dirty.current) { save(); pushLB(false); }
      if (n % 180 === 0) collectBank();
      force();
    }, 250);
    return () => clearInterval(iv);
  }, [ready, g, checkAch, save, pushLB, collectBank]);

  /* ── land mask ── */
  const mask = useRef(null);        // Uint8Array alpha
  const landCanvas = useRef(null);  // tinted land image
  const [maskReady, setMaskReady] = useState(false);
  useEffect(() => {
    const img = new Image();
    img.onload = () => {
      const oc = document.createElement("canvas");
      oc.width = MASK_W; oc.height = MASK_H;
      const c = oc.getContext("2d");
      c.drawImage(img, 0, 0);
      const d = c.getImageData(0, 0, MASK_W, MASK_H).data;
      const a = new Uint8Array(MASK_W * MASK_H);
      for (let i = 0; i < a.length; i++) a[i] = d[i * 4 + 3];
      mask.current = a;
      const tc = document.createElement("canvas");
      tc.width = MASK_W; tc.height = MASK_H;
      const t = tc.getContext("2d");
      t.drawImage(img, 0, 0);
      t.globalCompositeOperation = "source-in";
      t.fillStyle = C.landFill;
      t.fillRect(0, 0, MASK_W, MASK_H);
      landCanvas.current = tc;
      setMaskReady(true);
    };
    img.src = "data:image/png;base64," + LAND_B64;
  }, []);

  const landness = useCallback((wx, wy) => {
    const a = mask.current;
    if (!a) return 0;
    const mx = wx * MASK_W - 0.5, my = wy * MASK_H - 0.5;
    const x0 = Math.floor(mx), y0 = Math.floor(my);
    const fx = mx - x0, fy = my - y0;
    const at = (x, y) => {
      x = ((x % MASK_W) + MASK_W) % MASK_W;
      y = Math.max(0, Math.min(MASK_H - 1, y));
      return a[y * MASK_W + x];
    };
    const v = at(x0, y0) * (1 - fx) * (1 - fy) + at(x0 + 1, y0) * fx * (1 - fy) +
              at(x0, y0 + 1) * (1 - fx) * fy + at(x0 + 1, y0 + 1) * fx * fy;
    return v / 255;
  }, []);

  const clsCache = useRef(new Map());
  const classifyTxy = useCallback((tx, ty) => {
    const cc = clsCache.current;
    const key = ty * N + tx;
    let v = cc.get(key);
    if (v) return v;
    const l = landness((tx + 0.5) / N, (ty + 0.5) / N);
    v = l >= 0.8 ? "land" : l >= 0.2 ? "coast" : "water";
    if (cc.size > 60000) cc.clear();
    cc.set(key, v);
    return v;
  }, [landness]);
  const classify = useCallback((qk) => {
    const [tx, ty] = txyOf(qk);
    return classifyTxy(tx, ty);
  }, [classifyTxy]);

  /* ── shared world regions ── */
  const ensureRegion = useCallback(async (prefix, forceRefresh) => {
    const rc = regions.current;
    const cur = rc.get(prefix);
    if (!forceRefresh && cur && Date.now() - cur.at < 25000) return cur;
    if (busyRegions.current.has(prefix)) return cur;
    busyRegions.current.add(prefix);
    setSyncing(true);
    const raw = await store.get("w:" + prefix, true);
    let obj = { t: {} };
    if (raw) { try { obj = JSON.parse(raw) || { t: {} }; } catch { obj = { t: {} }; } }
    obj.at = Date.now();
    rc.set(prefix, obj);
    // reconcile: recover tiles deeded to me that I lost track of; drop ones I no longer own
    let changed = false;
    for (const [qk, rec] of Object.entries(obj.t)) {
      const mine = ownMap.current.get(qk);
      if (rec.o === g.pid && !mine) {
        g.own.push({ qk, l: rec.l || 0, r: rec.r || 0, cls: classify(qk), pd: rec.pd || 0, p: rec.p });
        changed = true;
      } else if (mine) {
        if (rec.o !== g.pid) { g.own.splice(g.own.findIndex((t) => t.qk === qk), 1); changed = true; }
        else if (mine.p !== rec.p) { mine.p = rec.p; changed = true; }
      }
    }
    if (changed) { rebuildOwn(); dirty.current = true; }
    busyRegions.current.delete(prefix);
    setSyncing(busyRegions.current.size > 0);
    return obj;
  }, [g, classify, rebuildOwn]);

  const mutateRegion = useCallback(async (prefix, fn) => {
    const raw = await store.get("w:" + prefix, true);
    let obj = { t: {} };
    if (raw) { try { obj = JSON.parse(raw) || { t: {} }; } catch { obj = { t: {} }; } }
    const ok = fn(obj);
    if (ok === false) return { ok: false, obj };
    obj.at = Date.now();
    await store.set("w:" + prefix, JSON.stringify({ t: obj.t }), true);
    regions.current.set(prefix, obj);
    return { ok: true, obj };
  }, []);

  const recOf = (qk) => {
    const r = regions.current.get(regionOf(qk));
    return r ? r.t[qk] : undefined;
  };

  /* ── market index ── */
  const touchMarket = useCallback(async (fn) => {
    const raw = await store.get("mkt:list", true);
    let arr = [];
    if (raw) { try { arr = JSON.parse(raw) || []; } catch { arr = []; } }
    arr = fn(arr).filter((e) => Date.now() - (e.t || 0) < 7 * 86400e3).slice(-40);
    await store.set("mkt:list", JSON.stringify(arr), true);
    return arr;
  }, []);

  const refreshMarket = useCallback(async () => {
    setMarket({ loading: true, rows: null });
    const raw = await store.get("mkt:list", true);
    let arr = [];
    if (raw) { try { arr = JSON.parse(raw) || []; } catch { arr = []; } }
    setMarket({ loading: false, rows: arr.slice().reverse() });
  }, []);
  useEffect(() => { if (tab === "market") refreshMarket(); }, [tab, refreshMarket]);

  const refreshLB = useCallback(async () => {
    setLb({ loading: true, rows: null });
    const keys = (await store.list("lb:", true)).slice(0, 30);
    const rows = (await Promise.all(keys.map(async (k) => {
      const key = typeof k === "string" ? k : k.key;
      const v = await store.get(key, true);
      if (!v) return null;
      try { return { id: key.slice(3), ...JSON.parse(v) }; } catch { return null; }
    }))).filter(Boolean);
    rows.sort((a, b) => (b.nw || 0) - (a.nw || 0));
    setLb({ loading: false, rows: rows.slice(0, 10) });
  }, []);
  useEffect(() => { if (tab === "hq") refreshLB(); }, [tab, refreshLB]);

  /* ── actions ── */
  const needName = () => {
    if (g.name) return false;
    setModal({ kind: "name" });
    return true;
  };

  const buyUnowned = async (qk) => {
    if (roll || needName()) return;
    const cls = classify(qk);
    const price = CLS[cls].price;
    if (g.bal < price) return;
    g.bal -= price;
    setRoll({ qk, phase: "spin" });
    const r = rollRarity();
    const res = await mutateRegion(regionOf(qk), (obj) => {
      if (obj.t[qk]) return false; // someone got here first
      obj.t[qk] = { o: g.pid, n: g.name, l: 0, r, pd: price };
    });
    if (!res.ok) {
      g.bal += price;
      setRoll(null);
      toast("Beaten to it — another player owns that tile. Refunded.");
      dirty.current = true;
      return;
    }
    g.own.push({ qk, l: 0, r, cls, pd: price });
    rebuildOwn(); checkAch(); dirty.current = true; save(); pushLB(true);
    setTimeout(() => setRoll({ qk, phase: "done", r }), reduced ? 50 : 900);
    if (r === 3) toast("Legendary deed!");
  };

  const buyListed = async (qk) => {
    if (needName()) return;
    const rec = recOf(qk);
    if (!rec) { toast("Tile not synced yet \u2014 one moment, then try again."); return; }
    if (!rec.p || rec.o === g.pid) return;
    const price = rec.p, seller = rec.o;
    if (g.bal < price) return;
    g.bal -= price;
    const res = await mutateRegion(regionOf(qk), (obj) => {
      const cur = obj.t[qk];
      if (!cur || cur.o !== seller || cur.p !== price) return false; // listing changed
      obj.t[qk] = { o: g.pid, n: g.name, l: cur.l || 0, r: cur.r || 0, pd: price };
    });
    if (!res.ok) { g.bal += price; toast("Listing changed — trade cancelled, refunded."); dirty.current = true; return; }
    const cur = res.obj.t[qk];
    g.own.push({ qk, l: cur.l, r: cur.r, cls: classify(qk), pd: price });
    rebuildOwn(); checkAch(); dirty.current = true; save(); pushLB(true);
    // pay the seller via their mailbox
    const braw = await store.get("bank:" + seller, true);
    let barr = [];
    if (braw) { try { barr = JSON.parse(braw) || []; } catch { barr = []; } }
    barr.push({ id: Math.random().toString(36).slice(2), amt: price, from: g.name, qk, t: Date.now() });
    await store.set("bank:" + seller, JSON.stringify(barr), true);
    touchMarket((arr) => arr.filter((e) => e.qk !== qk));
    toast(`Deed acquired from ${rec.n || "a player"}`);
  };

  const listTile = async (qk, price) => {
    const t = ownMap.current.get(qk);
    if (!t || !(price > 0)) return;
    const res = await mutateRegion(regionOf(qk), (obj) => {
      const cur = obj.t[qk];
      if (!cur || cur.o !== g.pid) return false;
      cur.p = price;
    });
    if (!res.ok) { toast("Couldn't list — deed not found under your name."); return; }
    t.p = price; dirty.current = true; save();
    touchMarket((arr) => [...arr.filter((e) => e.qk !== qk), { qk, p: price, n: g.name, cls: t.cls, t: Date.now() }]);
    toast(`Listed for ₲${fmt(price)}`);
  };

  const unlist = async (qk) => {
    const t = ownMap.current.get(qk);
    if (!t) return;
    await mutateRegion(regionOf(qk), (obj) => {
      const cur = obj.t[qk];
      if (!cur || cur.o !== g.pid) return false;
      delete cur.p;
    });
    delete t.p; dirty.current = true; save();
    touchMarket((arr) => arr.filter((e) => e.qk !== qk));
    toast("Listing removed");
  };

  const upgrade = async (qk) => {
    const t = ownMap.current.get(qk);
    if (!t || t.l >= MAX_LVL) return;
    const cost = upCost(t);
    if (g.bal < cost) return;
    g.bal -= cost; t.l++; t.pd += cost;
    await mutateRegion(regionOf(qk), (obj) => {
      const cur = obj.t[qk];
      if (cur && cur.o === g.pid) { cur.l = t.l; cur.pd = t.pd; }
    });
    rebuildOwn(); checkAch(); dirty.current = true; save(); pushLB(true);
    toast(`${LVL[t.l]} built`);
  };

  const abandon = async (qk) => {
    const t = ownMap.current.get(qk);
    if (!t) return;
    const refund = Math.round((t.pd || 0) * 0.5);
    await mutateRegion(regionOf(qk), (obj) => {
      const cur = obj.t[qk];
      if (cur && cur.o === g.pid) delete obj.t[qk];
    });
    touchMarket((arr) => arr.filter((e) => e.qk !== qk));
    g.own.splice(g.own.findIndex((x) => x.qk === qk), 1);
    g.bal += refund;
    rebuildOwn(); dirty.current = true; save(); pushLB(true);
    toast(`Sold to the void for ₲${fmt(refund)}`);
  };

  const claimBoost = () => {
    g.boostUntil = Date.now() + 5 * 60 * 1000;
    dirty.current = true; save(); setModal(null);
    toast("2× rent for 5 minutes");
  };

  const closeModal = () => {
    if (pendings.current.length) setModal(pendings.current.shift());
    else setModal(null);
  };

  const setName = () => {
    const n = nameDraft.trim().slice(0, 16);
    if (!n) return;
    g.name = n; dirty.current = true; save(); pushLB(true);
    setModal(null);
    toast("Deeds will be signed as " + n);
  };

  /* ── camera & canvas ── */
  const wrapRef = useRef(null);
  const canvasRef = useRef(null);
  const cam = useRef({ x: 0, y: 0, s: 300, init: false }); // s = world width in px
  const size = useRef({ w: 0, h: 0, dpr: 1 });
  const frame = useRef(0);
  const ptrs = useRef(new Map());
  const gesture = useRef(null);

  const fitWorld = useCallback(() => {
    const { w, h } = size.current;
    const s = Math.min(w, h * 2) * 0.95;
    cam.current = { s, x: (w - s) / 2, y: (h - s) / 2, init: true };
  }, []);

  const flyTo = useCallback((lat, lon, tilePx = 16) => {
    const { w, h } = size.current;
    const s = N * tilePx;
    const wx = lonToWx(lon), wy = latToWy(lat);
    cam.current = { s, x: w / 2 - wx * s, y: h / 2 - wy * s, init: true };
    setCities(false);
  }, []);

  useEffect(() => {
    const el = wrapRef.current, cv = canvasRef.current;
    if (!el || !cv) return;
    const measure = () => {
      const r = el.getBoundingClientRect();
      const dpr = Math.min(window.devicePixelRatio || 1, 2);
      if (size.current.w === r.width && size.current.h === r.height && size.current.dpr === dpr && cam.current.init) return;
      size.current = { w: r.width, h: r.height, dpr };
      cv.width = r.width * dpr; cv.height = r.height * dpr;
      cv.style.width = r.width + "px"; cv.style.height = r.height + "px";
      if (!cam.current.init && r.width > 0) fitWorld();
    };
    measure();
    const ro = new ResizeObserver(measure);
    ro.observe(el);
    return () => ro.disconnect();
  }, [fitWorld]);

  const hexA = (hex, a) => {
    const n = parseInt(hex.slice(1), 16);
    return `rgba(${(n >> 16) & 255},${(n >> 8) & 255},${n & 255},${a})`;
  };

  const drawBuilding = (ctx, px, py, cs, lvl, seed) => {
    const f = frame.current;
    const win = (idx) => (reduced ? true : ((seed * 31 + idx * 7 + (f >> 4)) % 13) !== 0);
    const A = C.amber;
    if (lvl === 0) {
      ctx.fillStyle = A;
      const s2 = cs * 0.16;
      ctx.beginPath();
      ctx.moveTo(px + cs / 2, py + cs / 2 - s2); ctx.lineTo(px + cs / 2 + s2, py + cs / 2);
      ctx.lineTo(px + cs / 2, py + cs / 2 + s2); ctx.lineTo(px + cs / 2 - s2, py + cs / 2);
      ctx.closePath(); ctx.fill();
      return;
    }
    ctx.fillStyle = "#3A4A63";
    if (lvl === 1) {
      ctx.fillRect(px + cs * 0.25, py + cs * 0.55, cs * 0.5, cs * 0.3);
      if (win(0)) { ctx.fillStyle = A; ctx.fillRect(px + cs * 0.45, py + cs * 0.62, cs * 0.1, cs * 0.1); }
    } else if (lvl === 2) {
      ctx.fillRect(px + cs * 0.14, py + cs * 0.45, cs * 0.32, cs * 0.4);
      ctx.fillRect(px + cs * 0.54, py + cs * 0.45, cs * 0.32, cs * 0.4);
      ctx.fillStyle = A;
      if (win(0)) ctx.fillRect(px + cs * 0.24, py + cs * 0.55, cs * 0.1, cs * 0.1);
      if (win(1)) ctx.fillRect(px + cs * 0.64, py + cs * 0.55, cs * 0.1, cs * 0.1);
    } else if (lvl === 3) {
      ctx.fillRect(px + cs * 0.28, py + cs * 0.3, cs * 0.44, cs * 0.58);
      ctx.fillStyle = A;
      for (let i = 0; i < 4; i++) if (win(i))
        ctx.fillRect(px + cs * (0.34 + (i % 2) * 0.2), py + cs * (0.38 + Math.floor(i / 2) * 0.24), cs * 0.1, cs * 0.12);
    } else {
      ctx.fillStyle = "#42536F";
      ctx.fillRect(px + cs * 0.3, py + cs * 0.22, cs * 0.4, cs * 0.7);
      ctx.fillRect(px + cs * 0.48, py + cs * 0.1, cs * 0.04, cs * 0.12);
      ctx.fillStyle = A;
      for (let i = 0; i < 6; i++) if (win(i))
        ctx.fillRect(px + cs * (0.36 + (i % 2) * 0.18), py + cs * (0.28 + Math.floor(i / 2) * 0.21), cs * 0.09, cs * 0.11);
    }
  };

  const draw = useCallback(() => {
    const cv = canvasRef.current;
    if (!cv) return;
    const ctx = cv.getContext("2d");
    const { w, h, dpr } = size.current;
    const { x: ox, y: oy, s } = cam.current;
    ctx.setTransform(dpr, 0, 0, dpr, 0, 0);
    ctx.fillStyle = C.oceanDeep;
    ctx.fillRect(0, 0, w, h);
    ctx.fillStyle = C.ocean;
    ctx.fillRect(ox, oy, s, s);

    const tilePx = s / N;

    /* terrain: draw only the visible slice of the land image — a full
       (s × s) destination rect reaches millions of px at deep zoom and
       freezes the GPU */
    const dx = Math.max(ox, 0), dy = Math.max(oy, 0);
    const dx1 = Math.min(ox + s, w), dy1 = Math.min(oy + s, h);
    if (landCanvas.current && dx1 > dx && dy1 > dy) {
      const sx = ((dx - ox) / s) * MASK_W, sy = ((dy - oy) / s) * MASK_H;
      const sw = Math.max(((dx1 - dx) / s) * MASK_W, 1e-4);
      const sh = Math.max(((dy1 - dy) / s) * MASK_H, 1e-4);
      ctx.imageSmoothingEnabled = tilePx < 6;
      ctx.drawImage(landCanvas.current, sx, sy, sw, sh, dx, dy, dx1 - dx, dy1 - dy);
    }

    const gridOn = tilePx >= 8;

    if (gridOn) {
      const tx0 = Math.max(0, Math.floor(-ox / tilePx));
      const ty0 = Math.max(0, Math.floor(-oy / tilePx));
      const tx1 = Math.min(N - 1, Math.ceil((w - ox) / tilePx));
      const ty1 = Math.min(N - 1, Math.ceil((h - oy) / tilePx));
      const cnt = (tx1 - tx0 + 1) * (ty1 - ty0 + 1);

      /* coast tint: per-tile, but cached under numeric keys and skipped
         when the viewport holds too many tiles */
      if (cnt <= 6500) {
        ctx.fillStyle = hexA(CLS.coast.color, 0.12);
        for (let ty = ty0; ty <= ty1; ty++) for (let tx = tx0; tx <= tx1; tx++) {
          if (classifyTxy(tx, ty) === "coast") {
            ctx.fillRect(ox + tx * tilePx, oy + ty * tilePx, tilePx, tilePx);
          }
        }
      }

      /* grid as a few hundred batched lines instead of ~20k strokeRects */
      ctx.strokeStyle = hexA("#8DA0B8", 0.12);
      ctx.lineWidth = 1;
      ctx.beginPath();
      for (let tx = tx0; tx <= tx1 + 1; tx++) { const px = ox + tx * tilePx; ctx.moveTo(px, dy); ctx.lineTo(px, dy1); }
      for (let ty = ty0; ty <= ty1 + 1; ty++) { const py = oy + ty * tilePx; ctx.moveTo(dx, py); ctx.lineTo(dx1, py); }
      ctx.stroke();

      /* owned & listed tiles: iterate sparse region records, not every tile */
      for (const prefix of prefixesFor(cam.current, size.current)) {
        const reg = regions.current.get(prefix);
        if (!reg) continue;
        for (const [qk, rec] of Object.entries(reg.t)) {
          const [tx, ty] = txyOf(qk);
          if (tx < tx0 || tx > tx1 || ty < ty0 || ty > ty1) continue;
          const px = ox + tx * tilePx, py = oy + ty * tilePx;
          const mine = rec.o === g.pid;
          ctx.fillStyle = hexA(mine ? C.amber : CLS[classifyTxy(tx, ty)].color, mine ? 0.28 : 0.3);
          ctx.fillRect(px + 1, py + 1, tilePx - 2, tilePx - 2);
          if (rec.r === 3) {
            const pulse = reduced ? 0.8 : 0.55 + 0.35 * Math.sin(frame.current / 12 + tx + ty);
            ctx.strokeStyle = hexA(C.amber, pulse);
            ctx.lineWidth = 2;
            ctx.strokeRect(px + 1, py + 1, tilePx - 2, tilePx - 2);
            ctx.lineWidth = 1;
          }
          if (tilePx > 13) drawBuilding(ctx, px, py, tilePx, rec.l || 0, tx * 7 + ty);
          if (rec.p) {
            ctx.fillStyle = C.amber;
            ctx.beginPath(); ctx.arc(px + tilePx - 4, py + 4, 2.6, 0, 7); ctx.fill();
          }
        }
      }
    } else {
      // empire view: your deeds as glowing dots
      ctx.fillStyle = C.amber;
      let i = 0;
      for (const t of g.own) {
        if (i++ > 800) break;
        const [wx, wy] = centerOfQk(t.qk);
        const px = ox + wx * s, py = oy + wy * s;
        if (px < -4 || py < -4 || px > w + 4 || py > h + 4) continue;
        ctx.beginPath(); ctx.arc(px, py, Math.max(1.6, tilePx * 2), 0, 7); ctx.fill();
      }
    }

    if (sel) {
      const [tx, ty] = txyOf(sel);
      const px = ox + tx * tilePx, py = oy + ty * tilePx;
      ctx.strokeStyle = C.amber; ctx.lineWidth = 2;
      ctx.strokeRect(px + 0.5, py + 0.5, tilePx - 1, tilePx - 1);
      ctx.lineWidth = 1;
    }

    /* scale bar (real scale at screen-centre latitude) */
    const midWy = (h / 2 - oy) / s;
    if (midWy > 0 && midWy < 1) {
      const lat = wyToLat(midWy);
      const mpp = (40075016 * Math.cos((lat * Math.PI) / 180)) / s;
      let target = mpp * 110;
      const pow = Math.pow(10, Math.floor(Math.log10(target)));
      const nice = [1, 2, 5, 10].map((k) => k * pow).reduce((a, b) => (Math.abs(b - target) < Math.abs(a - target) ? b : a));
      const barPx = nice / mpp;
      const label = nice >= 1000 ? (nice / 1000).toLocaleString() + " km" : Math.round(nice) + " m";
      const bx = 14, by = h - 16;
      ctx.strokeStyle = C.text; ctx.lineWidth = 1.5;
      ctx.beginPath();
      ctx.moveTo(bx, by - 4); ctx.lineTo(bx, by); ctx.lineTo(bx + barPx, by); ctx.lineTo(bx + barPx, by - 4);
      ctx.stroke();
      ctx.fillStyle = C.text;
      ctx.font = "10px ui-monospace, Menlo, monospace";
      ctx.fillText(label, bx + 4, by - 6);
      ctx.lineWidth = 1;
    }
  }, [g, sel, classifyTxy, reduced]);

  useEffect(() => {
    if (!ready || tab !== "map" || !maskReady) return;
    let raf, last = 0;
    const loop = (t) => {
      if (t - last > 33) { last = t; frame.current++; draw(); }
      raf = requestAnimationFrame(loop);
    };
    raf = requestAnimationFrame(loop);
    return () => cancelAnimationFrame(raf);
  }, [ready, tab, maskReady, draw]);

  /* region sync for viewport */
  useEffect(() => {
    if (!ready) return;
    const iv = setInterval(() => {
      if (tab !== "map") return;
      if (cam.current.s / N < 8) return;
      for (const q of prefixesFor(cam.current, size.current)) ensureRegion(q, false);
    }, 1200);
    return () => clearInterval(iv);
  }, [ready, tab, ensureRegion]);

  /* pointer input */
  const zoomAt = (mx, my, ns) => {
    const c = cam.current;
    const { w, h } = size.current;
    ns = Math.max(Math.min(w, h * 2) * 0.7, Math.min(N * 64, ns));
    const k = ns / c.s;
    cam.current = { s: ns, x: mx - (mx - c.x) * k, y: my - (my - c.y) * k, init: true };
  };
  const onDown = (e) => {
    const cv = canvasRef.current;
    cv.setPointerCapture(e.pointerId);
    const r = cv.getBoundingClientRect();
    ptrs.current.set(e.pointerId, { x: e.clientX - r.left, y: e.clientY - r.top });
    const pts = [...ptrs.current.values()];
    if (pts.length === 1) gesture.current = { kind: "pan", sx: pts[0].x, sy: pts[0].y, ox: cam.current.x, oy: cam.current.y, moved: false };
    else if (pts.length === 2) {
      const d = Math.hypot(pts[0].x - pts[1].x, pts[0].y - pts[1].y);
      gesture.current = { kind: "pinch", d0: d, s0: cam.current.s, moved: true };
    }
  };
  const onMove = (e) => {
    if (!ptrs.current.has(e.pointerId)) return;
    const r = canvasRef.current.getBoundingClientRect();
    ptrs.current.set(e.pointerId, { x: e.clientX - r.left, y: e.clientY - r.top });
    const gst = gesture.current;
    const pts = [...ptrs.current.values()];
    if (!gst) return;
    if (gst.kind === "pan" && pts.length === 1) {
      const dx = pts[0].x - gst.sx, dy = pts[0].y - gst.sy;
      if (Math.abs(dx) + Math.abs(dy) > 7) gst.moved = true;
      if (gst.moved) { cam.current.x = gst.ox + dx; cam.current.y = gst.oy + dy; }
    } else if (gst.kind === "pinch" && pts.length === 2) {
      const d = Math.hypot(pts[0].x - pts[1].x, pts[0].y - pts[1].y);
      const mx = (pts[0].x + pts[1].x) / 2, my = (pts[0].y + pts[1].y) / 2;
      zoomAt(mx, my, gst.s0 * (d / gst.d0));
    }
  };
  const onUp = (e) => {
    const gst = gesture.current;
    const wasTap = gst && gst.kind === "pan" && !gst.moved && ptrs.current.size === 1;
    const pt = ptrs.current.get(e.pointerId);
    ptrs.current.delete(e.pointerId);
    if (wasTap && pt) {
      const { s, x: ox, y: oy } = cam.current;
      const tilePx = s / N;
      if (tilePx >= 8) {
        const tx = Math.floor((pt.x - ox) / tilePx), ty = Math.floor((pt.y - oy) / tilePx);
        if (tx >= 0 && ty >= 0 && tx < N && ty < N) {
          const qk = qkOf(tx, ty);
          setSel(qk); setRoll(null);
          ensureRegion(regionOf(qk), false);
        } else setSel(null);
      } else {
        zoomAt(pt.x, pt.y, cam.current.s * 3.2);
      }
    }
    if (ptrs.current.size === 0) gesture.current = null;
  };
  const onWheel = (e) => {
    const r = canvasRef.current.getBoundingClientRect();
    zoomAt(e.clientX - r.left, e.clientY - r.top, cam.current.s * (e.deltaY < 0 ? 1.25 : 0.8));
  };

  /* ── render ── */
  if (!ready || !maskReady) {
    return (
      <div className="flex h-screen w-full items-center justify-center" style={{ background: C.ink, color: C.dim, ...mono }}>
        Unrolling the planet…
      </div>
    );
  }

  const boostLeft = Math.max(0, g.boostUntil - Date.now());
  const boostOn = boostLeft > 0;
  const mmss = (ms) => { const s = Math.ceil(ms / 1000); return `${Math.floor(s / 60)}:${String(s % 60).padStart(2, "0")}`; };

  const selRec = sel ? recOf(sel) : undefined;
  const selMine = sel ? ownMap.current.get(sel) : undefined;
  const selCls = sel ? classify(sel) : null;
  const tilePxNow = cam.current.s / N;

  return (
    <div className="relative flex h-screen w-full flex-col overflow-hidden select-none" style={{ background: C.ink, color: C.text }}>
      <style>{`.pt9{font-size:9px}.pt10{font-size:10px}.pt11{font-size:11px}.trk{letter-spacing:.22em}`}</style>

      {/* ticker */}
      <div className="flex items-center justify-between gap-3 px-4 pb-2 pt-3" style={{ borderBottom: `1px solid ${C.hair}`, background: C.panel }}>
        <div className="min-w-0">
          <button onClick={() => { save(); onExit(); }} className="pt9 trk uppercase focus-visible:outline focus-visible:outline-2" style={{ ...mono, color: C.dim, outlineColor: C.amber }}>
            ‹ Plot Twist · World Deed
          </button>
          <div className="flex items-baseline gap-2">
            <div className="text-2xl font-bold" style={{ ...mono, color: C.amber, fontVariantNumeric: "tabular-nums" }}>₲{fmt(g.bal)}</div>
            <div className="text-xs" style={{ ...mono, color: C.dim }}>+{fmt1(g.rps * (boostOn ? 2 : 1))}/s{boostOn ? " ⚡" : ""}</div>
          </div>
        </div>
        {boostOn ? (
          <div className="rounded-lg px-3 py-2 text-xs font-bold" style={{ ...mono, color: C.amber, border: `1px solid ${C.amber}66`, fontVariantNumeric: "tabular-nums" }}>
            2× {mmss(boostLeft)}
          </div>
        ) : (
          <Btn small onClick={() => setModal({ kind: "ad", ad: ADS[(Math.random() * ADS.length) | 0] })}>⚡ 2× boost</Btn>
        )}
      </div>

      {/* body */}
      <div className="relative flex-1 overflow-hidden">
        <div ref={wrapRef} className={`absolute inset-0 ${tab === "map" ? "" : "hidden"}`}>
          <canvas
            ref={canvasRef}
            className="h-full w-full touch-none"
            onPointerDown={onDown} onPointerMove={onMove} onPointerUp={onUp} onPointerCancel={onUp} onWheel={onWheel}
          />
          {/* controls */}
          <div className="absolute right-3 top-3 flex flex-col gap-1.5">
            {[
              ["+", () => zoomAt(size.current.w / 2, size.current.h / 2, cam.current.s * 1.6)],
              ["−", () => zoomAt(size.current.w / 2, size.current.h / 2, cam.current.s * 0.62)],
              ["🌐", fitWorld],
              ["✈", () => setCities((c) => !c)],
            ].map(([t, fn]) => (
              <button key={t} onClick={fn} className="h-9 w-9 rounded-lg text-sm focus-visible:outline focus-visible:outline-2"
                style={{ ...mono, background: C.panel + "e6", color: C.text, border: `1px solid ${C.hair}`, outlineColor: C.amber }}>
                {t}
              </button>
            ))}
          </div>
          {cities && (
            <div className="absolute right-14 top-3 rounded-xl p-2" style={{ background: C.panel + "f2", border: `1px solid ${C.hair}` }}>
              {CITIES.map(([name, lat, lon]) => (
                <button key={name} onClick={() => flyTo(lat, lon)} className="block w-full rounded px-2 py-1.5 text-left text-xs focus-visible:outline focus-visible:outline-2"
                  style={{ ...mono, color: C.text, outlineColor: C.amber }}>
                  {name}
                </button>
              ))}
            </div>
          )}
          {syncing && (
            <div className="pt10 absolute left-3 top-3 rounded-full px-2.5 py-1" style={{ ...mono, color: C.dim, background: C.panel + "e6", border: `1px solid ${C.hair}` }}>
              syncing deeds…
            </div>
          )}
          {tilePxNow < 8 && !sel && (
            <div className="pt10 pointer-events-none absolute inset-x-0 top-3 text-center" style={{ ...mono, color: C.dim }}>
              zoom in until the deed grid appears · tap to zoom
            </div>
          )}

          {/* tile sheet */}
          {sel && (
            <div className="absolute inset-x-0 bottom-0 rounded-t-2xl p-4" style={{ background: C.panel, borderTop: `1px solid ${C.hair}` }}>
              <div className="mb-2 flex items-start justify-between">
                <div>
                  <Eyebrow>{CLS[selCls].name}{selCls === "land" ? " · " + FLAVOR[Math.floor(hashQk(sel) * FLAVOR.length)] : ""}</Eyebrow>
                  <div className="text-lg font-bold" style={mono}>{coordLabel(sel)}</div>
                  <div className="pt10" style={{ ...mono, color: C.dim }}>tile #{sel.slice(-6)} · ~306 m square</div>
                </div>
                <button onClick={() => { setSel(null); setRoll(null); }} className="px-2 text-lg focus-visible:outline focus-visible:outline-2" style={{ color: C.dim, outlineColor: C.amber }}>✕</button>
              </div>

              {roll && roll.qk === sel && roll.phase === "spin" && (
                <div className="py-3 text-center text-sm font-bold" style={{ ...mono, color: C.amber }}>Recording deed… rolling rarity</div>
              )}
              {roll && roll.qk === sel && roll.phase === "done" && (
                <div className="py-2 text-center">
                  <div className="text-xl font-bold" style={{ ...mono, color: RAR[roll.r].color }}>{RAR[roll.r].name}!</div>
                  <div className="mt-1 text-xs" style={{ color: C.dim }}>Rent ×{RAR[roll.r].m} on this tile, forever.</div>
                </div>
              )}

              {!selRec && !(roll && roll.qk === sel) && (
                <div>
                  <div className="mb-3 flex items-center justify-between text-sm" style={mono}>
                    <span style={{ color: C.dim }}>Unclaimed · deed price</span>
                    <span className="font-bold">₲{fmt(CLS[selCls].price)}</span>
                  </div>
                  <Btn full onClick={() => buyUnowned(sel)} disabled={g.bal < CLS[selCls].price}>
                    {g.bal < CLS[selCls].price ? "Not enough ₲" : `Claim deed — ₲${fmt(CLS[selCls].price)}`}
                  </Btn>
                </div>
              )}

              {selRec && !selMine && !(roll && roll.qk === sel && roll.phase === "spin") && (
                <div>
                  <div className="mb-2 flex items-center gap-2">
                    <Chip color={RAR[selRec.r || 0].color}>{RAR[selRec.r || 0].name}</Chip>
                    <Chip color={CLS[selCls].color}>{LVL[selRec.l || 0]}</Chip>
                    <span className="text-xs" style={{ ...mono, color: C.dim }}>owned by {selRec.n || "a player"}</span>
                  </div>
                  {selRec.p ? (
                    <Btn full onClick={() => buyListed(sel)} disabled={g.bal < selRec.p}>
                      {g.bal < selRec.p ? "Not enough ₲" : `Buy from ${selRec.n || "player"} — ₲${fmt(selRec.p)}`}
                    </Btn>
                  ) : (
                    <div className="py-2 text-center text-xs" style={{ ...mono, color: C.dim }}>Not for sale. Try making friends.</div>
                  )}
                </div>
              )}

              {selMine && !(roll && roll.qk === sel && roll.phase === "spin") && (
                <div>
                  <div className="mb-2 flex flex-wrap items-center gap-2">
                    <Chip color={RAR[selMine.r].color}>{RAR[selMine.r].name}</Chip>
                    <Chip color={CLS[selCls].color}>{LVL[selMine.l]}</Chip>
                    <span className="text-xs" style={{ ...mono, color: C.amber }}>₲{fmt1(rentOf(selMine))}/s</span>
                    {selMine.p && <Chip color={C.amber}>Listed ₲{fmt(selMine.p)}</Chip>}
                  </div>
                  <div className="flex gap-2">
                    {selMine.l < MAX_LVL ? (
                      <Btn full onClick={() => upgrade(sel)} disabled={g.bal < upCost(selMine)}>
                        Build {LVL[selMine.l + 1]} — ₲{fmt(upCost(selMine))}
                      </Btn>
                    ) : (
                      <div className="flex-1 py-2 text-center text-xs" style={{ ...mono, color: C.dim }}>Fully built.</div>
                    )}
                    {selMine.p ? (
                      <Btn tone="ghost" onClick={() => unlist(sel)}>Unlist</Btn>
                    ) : (
                      <Btn tone="ghost" onClick={() => { setPriceDraft(String(Math.round((selMine.pd || CLS[selCls].price) * 1.5))); setModal({ kind: "list", qk: sel }); }}>List…</Btn>
                    )}
                    <Btn tone="danger" onClick={() => abandon(sel)}>50%</Btn>
                  </div>
                </div>
              )}
            </div>
          )}
        </div>

        {/* PORTFOLIO */}
        {tab === "assets" && (
          <div className="absolute inset-0 overflow-y-auto p-4">
            <div className="mb-3"><Eyebrow>Your holdings · {g.own.length} tile{g.own.length === 1 ? "" : "s"} · net worth ₲{fmt(netWorth())}</Eyebrow></div>
            {g.own.length === 0 && (
              <div className="rounded-xl p-6 text-center text-sm" style={{ background: C.panel, color: C.dim }}>
                You own nothing. The planet awaits — zoom in anywhere and claim your first ~300 m of it.
              </div>
            )}
            {g.own.slice().sort((a, b) => rentOf(b) - rentOf(a)).map((t) => (
              <div key={t.qk} className="mb-2 rounded-xl p-3" style={{ background: C.panel, border: `1px solid ${C.hair}` }}>
                <button className="flex w-full items-center justify-between text-left focus-visible:outline focus-visible:outline-2" style={{ outlineColor: C.amber }}
                  onClick={() => { setTab("map"); setSel(t.qk); const [wx, wy] = centerOfQk(t.qk); const { w, h } = size.current; const s = N * 16; cam.current = { s, x: w / 2 - wx * s, y: h / 2 - wy * s, init: true }; ensureRegion(regionOf(t.qk), true); }}>
                  <div className="flex min-w-0 items-center gap-2">
                    <span className="h-2.5 w-2.5 shrink-0 rounded-sm" style={{ background: CLS[t.cls].color }} />
                    <span className="truncate text-sm font-bold" style={mono}>{coordLabel(t.qk)}</span>
                    <Chip color={RAR[t.r].color}>{RAR[t.r].name}</Chip>
                  </div>
                  <span className="text-xs" style={{ ...mono, color: C.amber }}>₲{fmt1(rentOf(t))}/s</span>
                </button>
                <div className="mt-2 flex items-center justify-between">
                  <span className="pt11" style={{ ...mono, color: C.dim }}>{LVL[t.l]} · Lv {t.l}/{MAX_LVL}{t.p ? ` · listed ₲${fmt(t.p)}` : ""}</span>
                  <div className="flex gap-1.5">
                    {t.l < MAX_LVL && (
                      <Btn small onClick={() => upgrade(t.qk)} disabled={g.bal < upCost(t)}>₲{fmt(upCost(t))}</Btn>
                    )}
                    {t.p ? (
                      <Btn small tone="ghost" onClick={() => unlist(t.qk)}>Unlist</Btn>
                    ) : (
                      <Btn small tone="ghost" onClick={() => { setPriceDraft(String(Math.round((t.pd || CLS[t.cls].price) * 1.5))); setModal({ kind: "list", qk: t.qk }); }}>List</Btn>
                    )}
                  </div>
                </div>
              </div>
            ))}
          </div>
        )}

        {/* MARKET */}
        {tab === "market" && (
          <div className="absolute inset-0 overflow-y-auto p-4">
            <div className="mb-3 flex items-center justify-between">
              <Eyebrow>Open market · player listings</Eyebrow>
              <button onClick={refreshMarket} className="pt11 focus-visible:outline focus-visible:outline-2" style={{ ...mono, color: C.amber, outlineColor: C.amber }}>Refresh</button>
            </div>
            {market.loading && <div className="pt11 py-2" style={{ ...mono, color: C.dim }}>Checking the register…</div>}
            {market.rows && market.rows.length === 0 && (
              <div className="rounded-xl p-6 text-center text-sm" style={{ background: C.panel, color: C.dim }}>
                Nothing listed right now. List one of your tiles and set the market.
              </div>
            )}
            {market.rows && market.rows.map((e) => (
              <div key={e.qk} className="mb-2 flex items-center justify-between rounded-xl p-3" style={{ background: C.panel, border: `1px solid ${C.hair}` }}>
                <button className="min-w-0 text-left focus-visible:outline focus-visible:outline-2" style={{ outlineColor: C.amber }}
                  onClick={() => { setTab("map"); setSel(e.qk); const [wx, wy] = centerOfQk(e.qk); const { w, h } = size.current; const s = N * 16; cam.current = { s, x: w / 2 - wx * s, y: h / 2 - wy * s, init: true }; ensureRegion(regionOf(e.qk), true); }}>
                  <div className="flex items-center gap-2">
                    <span className="h-2.5 w-2.5 shrink-0 rounded-sm" style={{ background: (CLS[e.cls] || CLS.land).color }} />
                    <span className="truncate text-sm font-bold" style={mono}>{coordLabel(e.qk)}</span>
                  </div>
                  <div className="pt11 mt-0.5" style={{ ...mono, color: C.dim }}>by {e.n || "a player"}{e.n === g.name ? " (you)" : ""}</div>
                </button>
                <div className="flex shrink-0 items-center gap-2">
                  <span className="text-sm font-bold" style={{ ...mono, color: C.amber }}>₲{fmt(e.p)}</span>
                  {e.n !== g.name && (
                    <Btn small onClick={async () => { await ensureRegion(regionOf(e.qk), true); buyListed(e.qk); }} disabled={g.bal < e.p}>Buy</Btn>
                  )}
                </div>
              </div>
            ))}
            <div className="pt10 mt-2 text-center" style={{ ...mono, color: C.dim }}>
              Listings are public to all players. Sales pay the seller even while they're offline.
            </div>
          </div>
        )}

        {/* HQ */}
        {tab === "hq" && (
          <div className="absolute inset-0 overflow-y-auto p-4">
            <div className="mb-3 grid grid-cols-2 gap-2">
              {[
                ["Net worth", "₲" + fmt(netWorth())],
                ["Rent rate", "₲" + fmt1(g.rps) + "/s"],
                ["Tiles", g.own.length],
                ["Visit streak", (g.streak || 0) + "d"],
              ].map(([k, v]) => (
                <div key={k} className="rounded-xl p-3" style={{ background: C.panel, border: `1px solid ${C.hair}` }}>
                  <div className="pt9 trk uppercase" style={{ ...mono, color: C.dim }}>{k}</div>
                  <div className="text-lg font-bold" style={{ ...mono, fontVariantNumeric: "tabular-nums" }}>{v}</div>
                </div>
              ))}
            </div>

            <div className="mb-3 rounded-xl p-3" style={{ background: C.panel, border: `1px solid ${C.hair}` }}>
              <div className="mb-2"><Eyebrow>Landlord identity</Eyebrow></div>
              {g.name ? (
                <div className="flex items-center justify-between">
                  <span className="text-sm font-bold" style={mono}>{g.name}</span>
                  <Btn small tone="ghost" onClick={() => { setNameDraft(g.name); setModal({ kind: "name" }); }}>Rename</Btn>
                </div>
              ) : (
                <div className="flex items-center justify-between">
                  <span className="text-xs" style={{ color: C.dim }}>Pick a name to claim tiles and trade.</span>
                  <Btn small onClick={() => setModal({ kind: "name" })}>Set name</Btn>
                </div>
              )}
              <div className="pt10 mt-2" style={{ ...mono, color: C.dim }}>
                Your name appears publicly on tiles you own, market listings and the leaderboard.
              </div>
            </div>

            <div className="mb-3 rounded-xl p-3" style={{ background: C.panel, border: `1px solid ${C.hair}` }}>
              <div className="mb-2"><Eyebrow>Commendations</Eyebrow></div>
              <div className="flex flex-wrap gap-1.5">
                {ACH.map((a) => (
                  <span key={a.k} title={a.desc} className="pt10 rounded px-2 py-1 font-bold"
                    style={{ ...mono, color: g.ach[a.k] ? "#221A05" : C.dim, background: g.ach[a.k] ? C.amber : "transparent", border: `1px solid ${g.ach[a.k] ? C.amber : C.hair}` }}>
                    {a.name}
                  </span>
                ))}
              </div>
            </div>

            <div className="mb-3 rounded-xl p-3" style={{ background: C.panel, border: `1px solid ${C.hair}` }}>
              <div className="mb-2 flex items-center justify-between">
                <Eyebrow>World register · top landlords</Eyebrow>
                <button onClick={refreshLB} className="pt11 focus-visible:outline focus-visible:outline-2" style={{ ...mono, color: C.amber, outlineColor: C.amber }}>Refresh</button>
              </div>
              {lb.loading ? (
                <div className="pt11 py-2" style={{ ...mono, color: C.dim }}>Pulling records…</div>
              ) : lb.rows && lb.rows.length ? (
                lb.rows.map((r, idx) => (
                  <div key={r.id} className="flex items-center justify-between py-1.5 text-sm" style={{ borderTop: idx ? `1px solid ${C.hair}` : "none" }}>
                    <div className="flex items-center gap-2" style={mono}>
                      <span className="w-5 text-right text-xs" style={{ color: C.dim }}>{idx + 1}</span>
                      <span className={r.id === g.pid ? "font-bold" : ""} style={r.id === g.pid ? { color: C.amber } : {}}>
                        {r.n}{r.id === g.pid ? " (you)" : ""}
                      </span>
                    </div>
                    <span className="text-xs" style={{ ...mono, color: C.dim }}>₲{fmt(r.nw || 0)} · {r.pc || 0} tiles</span>
                  </div>
                ))
              ) : (
                <div className="pt11 py-2" style={{ ...mono, color: C.dim }}>{g.name ? "No landlords on record yet." : "Set a name to appear here."}</div>
              )}
            </div>

            {!persistent && (
              <div className="mb-3 rounded-xl p-3 text-xs" style={{ background: "#2A2113", color: C.amber, border: `1px solid ${C.amber}44` }}>
                Preview mode: nothing persists and there are no other players in this environment.
              </div>
            )}
            <div className="pt10 pb-2 text-center leading-relaxed" style={{ ...mono, color: C.dim }}>
              Parody idle game. ₲ Geobux are virtual and worth nothing.<br />
              Coastlines are real (Natural Earth data) but simplified — your beach house may be approximate.
            </div>
          </div>
        )}
      </div>

      {/* toasts */}
      <div className="pointer-events-none absolute inset-x-0 bottom-20 z-10 flex flex-col items-center gap-1.5">
        {toasts.map((t) => (
          <div key={t.id} className="rounded-full px-4 py-1.5 text-xs font-bold" style={{ ...mono, background: C.amber, color: "#221A05" }}>{t.text}</div>
        ))}
      </div>

      {/* nav */}
      <div className="flex" style={{ background: C.panel, borderTop: `1px solid ${C.hair}` }}>
        {[["map", "Map"], ["assets", "Assets"], ["market", "Market"], ["hq", "HQ"]].map(([k, label]) => (
          <button key={k} onClick={() => setTab(k)} className="pt11 trk flex-1 py-3.5 font-bold uppercase focus-visible:outline focus-visible:outline-2"
            style={{ ...mono, color: tab === k ? C.amber : C.dim, boxShadow: tab === k ? `inset 0 2px 0 ${C.amber}` : "none", outlineColor: C.amber }}>
            {label}
          </button>
        ))}
      </div>

      {/* modals */}
      {modal && (
        <Modal onClose={closeModal}>
          {modal.kind === "welcome" && (
            <>
              <Eyebrow>While you were away</Eyebrow>
              <div className="my-2 text-2xl font-bold" style={{ ...mono, color: C.amber }}>+₲{fmt(modal.gain)}</div>
              <div className="mb-4 text-xs" style={{ color: C.dim }}>Your tenants kept paying (half rate, capped at 8h — even fake landlords need limits).</div>
              <Btn full onClick={closeModal}>Collect</Btn>
            </>
          )}
          {modal.kind === "daily" && (
            <>
              <Eyebrow>Daily stipend · day {modal.streak}</Eyebrow>
              <div className="my-2 text-2xl font-bold" style={{ ...mono, color: C.amber }}>+₲{fmt(modal.reward)}</div>
              <div className="mb-4 text-xs" style={{ color: C.dim }}>The World Deed Office pays you for showing up. Streak grows the stipend, up to day 7.</div>
              <Btn full onClick={closeModal}>Accept</Btn>
            </>
          )}
          {modal.kind === "name" && (
            <>
              <Eyebrow>Landlord identity</Eyebrow>
              <div className="mb-3 mt-2 text-xs" style={{ color: C.dim }}>
                Deeds are public records: this name is visible to every player on tiles you own, in listings, and on the leaderboard.
              </div>
              <div className="flex gap-2">
                <input value={nameDraft} onChange={(e) => setNameDraft(e.target.value)} maxLength={16} placeholder="e.g. DirtBaron"
                  className="min-w-0 flex-1 rounded-lg px-3 py-2 text-sm focus-visible:outline focus-visible:outline-2"
                  style={{ ...mono, background: C.ink, color: C.text, border: `1px solid ${C.hair}`, outlineColor: C.amber }} />
                <Btn small onClick={setName} disabled={!nameDraft.trim()}>Save</Btn>
              </div>
            </>
          )}
          {modal.kind === "list" && (
            <>
              <Eyebrow>List {coordLabel(modal.qk)}</Eyebrow>
              <div className="mb-3 mt-2 text-xs" style={{ color: C.dim }}>
                Any player can buy it at this price. Proceeds land in your account even if you're offline.
              </div>
              <div className="flex gap-2">
                <input value={priceDraft} onChange={(e) => setPriceDraft(e.target.value.replace(/[^0-9]/g, ""))} inputMode="numeric" placeholder="Price in ₲"
                  className="min-w-0 flex-1 rounded-lg px-3 py-2 text-sm focus-visible:outline focus-visible:outline-2"
                  style={{ ...mono, background: C.ink, color: C.text, border: `1px solid ${C.hair}`, outlineColor: C.amber }} />
                <Btn small onClick={() => { const p = parseInt(priceDraft, 10); if (p > 0) { listTile(modal.qk, p); closeModal(); } }} disabled={!(parseInt(priceDraft, 10) > 0)}>List</Btn>
              </div>
            </>
          )}
          {modal.kind === "ad" && <AdModal ad={modal.ad} reduced={reduced} onClaim={claimBoost} onClose={closeModal} />}
        </Modal>
      )}
    </div>
  );
}

/* ── fake ad modal ──────────────────────────────────────────── */

function AdModal({ ad, reduced, onClaim, onClose }) {
  const [t, setT] = useState(0);
  const DUR = reduced ? 1 : 6;
  useEffect(() => {
    const iv = setInterval(() => setT((x) => Math.min(DUR, x + 0.1)), 100);
    return () => clearInterval(iv);
  }, [DUR]);
  const done = t >= DUR;
  return (
    <>
      <div className="flex items-center justify-between">
        <Eyebrow>Paid promotion · parody, not a real ad</Eyebrow>
        <button onClick={onClose} className="px-1 text-lg focus-visible:outline focus-visible:outline-2" style={{ color: C.dim, outlineColor: C.amber }}>✕</button>
      </div>
      <div className="my-4 rounded-xl p-5 text-center" style={{ background: C.ink, border: `1px dashed ${C.hair}` }}>
        <div className="text-lg font-bold" style={mono}>{ad.brand}</div>
        <div className="mt-1 text-sm italic" style={{ color: C.dim }}>“{ad.line}”</div>
      </div>
      <div className="mb-3 h-1.5 overflow-hidden rounded-full" style={{ background: C.hair }}>
        <div className="h-full rounded-full transition-all" style={{ width: `${(t / DUR) * 100}%`, background: C.amber }} />
      </div>
      <Btn full disabled={!done} onClick={onClaim}>
        {done ? "Claim 2× rent (5:00)" : `Enjoying this fine message… ${Math.ceil(DUR - t)}s`}
      </Btn>
    </>
  );
}
